local a={}a.__index=a;function Stack(b)local self={_length=0}setmetatable(self,a)if b then self:Extend(b)end;return self end;function a:Push(c)assert(c~=nil,"Stack can't work with nil values")local d=self._length+1;self[d]=c;self._length=d end;function a:Pop(e)local d=self._length;e=e or d;assert(e>0 and e<=d,"Stack out of range")local c=self[e]for f=e+1,d do self[f-1]=self[f]end;self[d]=nil;self._length=d-1;return c end;function a:Slice(e)local d=self._length;assert(e and e>0 and e<d,"Stack out of range")local g=Stack()for f=e+1,d do g:Push(self[f])self[f]=nil end;self._length=e;return g end;function a:Extend(b)local d=#b;for f=1,d do self:Push(b[f])end end;function a:Clear()local d=self._length;for f=1,d do self[f]=nil end;self._length=0 end;function a:Peek()return self[self._length]end;function a:Size()return self._length end;function a:IsEmpty()return self._length==0 end;function a:Clip(e)local d=self._length;assert(e and e>0,"Stack out of range")if e<d then for f=e+1,d do self[f]=nil end;self._length=e end end;function a:RemoveInPlace(h)local d=self._length;local i=Stack()local j=1;for f=1,d do if h(j,self[f])then i:Push(f)else j=j+1 end end;for f=i:Size(),1,-1 do self:Pop(i[f])end;self._length=j-1 end